411→    #[test]
412→    fn test_parse_comment() {
413→        let src = "; this is a comment\n";
414→        let m = parse(src, "test.spc").unwrap();
415→        assert_eq!(m.items.len(), 1);
416→        assert_eq!(m.items[0], Item::Comment("; this is a comment".to_string()));
417→    }
