419→    #[test]
420→    fn test_parse_global() {
421→        let src = ".global count 1\n";
422→        let m = parse(src, "test.spc").unwrap();
423→        assert_eq!(m.items.len(), 1);
424→        assert_eq!(
425→            m.items[0],
426→            Item::Global(Global {
427→                name: "count".to_string(),
428→                nwords: 1
429→            })
430→        );
431→    }
