497→    #[test]
498→    fn test_parse_proc_with_labels() {
499→        let src = "\
500→.proc puts 1
501→    loada 0
502→    storel 0
503→loop:
504→    loadl 0
505→    loadb
506→    dup
507→    jz done
508→    sys 1
509→    jmp loop
510→done:
511→    drop
512→    ret 1
513→.end
514→";
515→        let m = parse(src, "test.spc").unwrap();
516→        match &m.items[0] {
517→            Item::Proc(p) => {
518→                assert_eq!(p.name, "puts");
519→                assert_eq!(p.nlocals, 1);
520→                // Check that labels are parsed
521→                assert!(p.body.iter().any(|s| *s == Statement::Label("loop".to_string())));
522→                assert!(p.body.iter().any(|s| *s == Statement::Label("done".to_string())));
523→            }
524→            _ => panic!("expected Proc"),
525→        }
526→    }
