528→    #[test]
529→    fn test_parse_instruction_with_comment() {
530→        let src = "\
531→.proc test 0
532→    push 45              ; '-'
533→    sys 1                ; PUTC
534→.end
535→";
536→        let m = parse(src, "test.spc").unwrap();
537→        match &m.items[0] {
538→            Item::Proc(p) => {
539→                match &p.body[0] {
540→                    Statement::Instruction(i) => {
541→                        assert_eq!(i.mnemonic, "push");
542→                        assert_eq!(i.operand.as_deref(), Some("45"));
543→                        assert!(i.comment.as_ref().unwrap().contains("'-'"));
544→                    }
545→                    _ => panic!("expected instruction"),
546→                }
547→            }
548→            _ => panic!("expected Proc"),
549→        }
550→    }
