552→    #[test]
553→    fn test_parse_hello_spc() {
554→        let src = "\
555→; hello.spc — Hello World for pv24a P-Code VM
556→;
557→; Expected output: Hello\\n
558→
559→.data msg 72, 101, 108, 108, 111, 10, 0
560→
561→.proc main 0
562→    push msg
563→    call puts
564→    halt
565→.end
566→
567→.proc puts 1
568→    loada 0
569→    storel 0
570→loop:
571→    loadl 0
572→    loadb
573→    dup
574→    jz done
575→    sys 1
576→    loadl 0
577→    push 1
578→    add
579→    storel 0
580→    jmp loop
581→done:
582→    drop
583→    ret 1
584→.end
585→";
586→        let m = parse(src, "hello.spc").unwrap();
587→        assert_eq!(m.name, "hello");
588→        assert!(!m.has_metadata);
589→        assert!(m.exports.is_empty());
590→        assert!(m.externs.is_empty());
591→
592→        // Should have: 3 comments, 1 data, 2 procs = 6 items
593→        assert_eq!(m.items.len(), 6);
594→
595→        // Verify data
596→        match &m.items[3] {
597→            Item::Data(d) => {
598→                assert_eq!(d.name, "msg");
599→                assert_eq!(d.bytes, vec![72, 101, 108, 108, 111, 10, 0]);
600→            }
601→            _ => panic!("expected Data at index 3"),
602→        }
603→
604→        // Verify main proc
605→        match &m.items[4] {
606→            Item::Proc(p) => {
607→                assert_eq!(p.name, "main");
608→                assert_eq!(p.nlocals, 0);
609→            }
610→            _ => panic!("expected Proc at index 4"),
611→        }
612→    }
