616→        let src = "\
617→.module runtime
618→.export _p24p_write_int
619→.export _p24p_write_ln
620→.extern some_helper
621→
622→.proc _p24p_write_int 1
623→    enter 1
624→    loada 0
625→    halt
626→.end
627→
628→.proc _p24p_write_ln 0
