  1→//! Symbol table and validation for the pl24r linker.
  2→//!
  3→//! Collects symbols from parsed .spc modules, builds a global symbol table,
  4→//! and validates cross-module references (duplicates, unresolved externs,
  5→//! entry point, unused exports).
  6→
  7→use std::collections::{HashMap, HashSet};
  8→use std::fmt;
  9→
 10→use crate::parser::{Item, Module};
 11→
 12→/// The kind of symbol defined in a module.
 13→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
 14→pub enum SymbolKind {
 15→    Proc,
 16→    Global,
 17→    Data,
 18→    Const,
 19→}
 20→
 21→impl fmt::Display for SymbolKind {
 22→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 23→        match self {
 24→            SymbolKind::Proc => write!(f, "proc"),
 25→            SymbolKind::Global => write!(f, "global"),
 26→            SymbolKind::Data => write!(f, "data"),
 27→            SymbolKind::Const => write!(f, "const"),
 28→        }
 29→    }
 30→}
 31→
 32→/// A symbol defined in a specific module.
 33→#[derive(Debug, Clone, PartialEq)]
 34→pub struct Symbol {
 35→    pub name: String,
 36→    pub kind: SymbolKind,
 37→    pub module: String,
 38→    pub exported: bool,
 39→}
 40→
 41→/// Result of symbol table validation.
 42→#[derive(Debug, Clone, PartialEq)]
 43→pub struct SymbolTable {
 44→    /// All symbols across all modules, keyed by symbol name.
 45→    /// Only exported symbols are included.
 46→    pub exports: HashMap<String, Symbol>,
 47→    /// Warnings (e.g., unused exports).
 48→    pub warnings: Vec<String>,
 49→}
 50→
 51→/// An error found during symbol validation.
 52→#[derive(Debug, Clone, PartialEq)]
 53→pub struct SymbolError {
 54→    pub message: String,
 55→}
 56→
 57→impl fmt::Display for SymbolError {
 58→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 59→        write!(f, "{}", self.message)
 60→    }
 61→}
 62→
 63→impl std::error::Error for SymbolError {}
 64→
 65→/// Collect all symbols defined in a module, respecting export rules.
 66→fn collect_module_symbols(module: &Module) -> Vec<Symbol> {
 67→    let export_all = !module.has_metadata;
 68→    let export_set: HashSet<&str> = module.exports.iter().map(|s| s.as_str()).collect();
 69→
 70→    let mut symbols = Vec::new();
 71→
 72→    for item in &module.items {
 73→        let (name, kind) = match item {
 74→            Item::Proc(p) => (p.name.as_str(), SymbolKind::Proc),
 75→            Item::Global(g) => (g.name.as_str(), SymbolKind::Global),
 76→            Item::Data(d) => (d.name.as_str(), SymbolKind::Data),
 77→            Item::Const(c) => (c.name.as_str(), SymbolKind::Const),
 78→            Item::Comment(_) => continue,
 79→        };
 80→
 81→        let exported = export_all || export_set.contains(name);
 82→
 83→        symbols.push(Symbol {
 84→            name: name.to_string(),
 85→            kind,
 86→            module: module.name.clone(),
 87→            exported,
 88→        });
 89→    }
 90→
 91→    symbols
 92→}
 93→
 94→/// Build a global symbol table from multiple parsed modules and validate it.
 95→///
 96→/// Returns the symbol table on success, or a list of errors on failure.
 97→/// Warnings (unused exports) are included in the successful result.
 98→pub fn build_symbol_table(modules: &[Module]) -> Result<SymbolTable, Vec<SymbolError>> {
 99→    let mut errors = Vec::new();
100→    let mut exports: HashMap<String, Symbol> = HashMap::new();
101→
102→    // Collect all extern references across all modules.
103→    let mut all_externs: HashSet<String> = HashSet::new();
104→    for module in modules {
105→        for ext in &module.externs {
106→            all_externs.insert(ext.clone());
107→        }
108→    }
109→
110→    // Phase 1: Collect exported symbols, detect duplicates.
111→    for module in modules {
112→        let symbols = collect_module_symbols(module);
113→        for sym in symbols {
114→            if !sym.exported {
115→                continue;
116→            }
117→            if let Some(existing) = exports.get(&sym.name) {
118→                errors.push(SymbolError {
119→                    message: format!(
120→                        "duplicate symbol '{}': exported by both '{}' and '{}'",
121→                        sym.name, existing.module, sym.module
122→                    ),
123→                });
124→            } else {
125→                exports.insert(sym.name.clone(), sym);
126→            }
127→        }
128→    }
129→
130→    // Phase 2: Verify unresolved externs.
131→    for ext in &all_externs {
132→        if !exports.contains_key(ext) {
133→            errors.push(SymbolError {
134→                message: format!("unresolved extern '{ext}': not exported by any module"),
135→            });
136→        }
137→    }
138→
139→    // Phase 3: Verify exactly one main proc exists.
140→    let main_modules: Vec<&str> = modules
141→        .iter()
142→        .filter(|m| {
143→            m.items.iter().any(|item| matches!(item, Item::Proc(p) if p.name == "main"))
144→        })
145→        .map(|m| m.name.as_str())
146→        .collect();
147→
148→    match main_modules.len() {
149→        0 => errors.push(SymbolError {
150→            message: "no 'main' procedure found in any module".to_string(),
151→        }),
152→        1 => {} // exactly right
153→        _ => errors.push(SymbolError {
154→            message: format!(
155→                "multiple 'main' procedures found in modules: {}",
156→                main_modules.join(", ")
157→            ),
158→        }),
159→    }
160→
161→    if !errors.is_empty() {
162→        return Err(errors);
163→    }
164→
165→    // Phase 4: Warn on unused exports (exported but never referenced as extern).
166→    let mut warnings = Vec::new();
167→    for (name, sym) in &exports {
168→        if name == "main" {
169→            continue; // main is always used as the entry point
170→        }
171→        if !all_externs.contains(name) {
172→            warnings.push(format!(
173→                "unused export '{}' ({}) in module '{}'",
174→                name, sym.kind, sym.module
175→            ));
176→        }
177→    }
178→    warnings.sort();
179→
180→    Ok(SymbolTable { exports, warnings })
181→}
