        );

        let mod_b = parse_ok(
            "\
.global shared 1
.proc helper 0
    ret 0
.end
",
            "b.spc",
        );

        let linked = link(&[mod_a, mod_b]).unwrap();
        // Only one copy of 'shared'.
        assert_eq!(
            linked.globals.iter().filter(|g| g.name == "shared").count(),
            1
        );
    }

